"use client";

import { useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { useRouter } from "next/navigation";

export default function LoginPage() {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const supabase = createClient();

  const handleKakaoLogin = async () => {
    setLoading(true);
    const { error } = await supabase.auth.signInWithOAuth({
      provider: "kakao",
      options: {
        redirectTo: `${window.location.origin}/auth/callback`,
        scopes: "profile_nickname profile_image",
        skipBrowserRedirect: false,
      },
    });

    if (error) {
      console.error("Login error:", error);
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-b from-neutral-950 to-neutral-900 p-4">
      <Card className="w-full max-w-md p-8 space-y-8">
        <div className="text-center space-y-2">
          <h1 className="text-3xl font-bold">NightFlow</h1>
          <p className="text-neutral-500">클럽 테이블 경매 플랫폼</p>
        </div>

        <div className="space-y-4">
          <Button
            onClick={handleKakaoLogin}
            disabled={loading}
            className="w-full h-12 bg-[#FEE500] text-black hover:bg-[#FDD835]"
          >
            {loading ? "로그인 중..." : "카카오로 시작하기"}
          </Button>

          <p className="text-xs text-center text-neutral-500">
            로그인 시{" "}
            <a href="#" className="underline">
              서비스 이용약관
            </a>{" "}
            및{" "}
            <a href="#" className="underline">
              개인정보 처리방침
            </a>
            에 동의하게 됩니다.
          </p>
        </div>
      </Card>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card } from "@/components/ui/card";
import { toast } from "sonner";
import { generateSlug } from "@/lib/utils/slug";
import type { Area } from "@/types/database";

export default function MDSignupPage() {
  const router = useRouter();
  const supabase = createClient();
  const [loading, setLoading] = useState(false);
  const [authUser, setAuthUser] = useState<any>(null);
  const [formData, setFormData] = useState({
    name: "",
    phone: "",
    area: "" as Area | "",
    bank_name: "",
    bank_account: "",
  });

  useEffect(() => {
    supabase.auth.getUser().then(({ data: { user } }) => {
      if (!user) {
        router.push("/login");
        return;
      }
      setAuthUser(user);
      const kakaoName =
        user.user_metadata?.full_name || user.user_metadata?.name || "";
      setFormData((prev) => ({ ...prev, name: kakaoName }));
    });
  }, [router, supabase]);

  const formatBankAccount = (value: string, bankName: string) => {
    // 숫자만 추출
    const numbers = value.replace(/[^\d]/g, "");

    // 은행별 포맷 적용 및 최대 자릿수 제한
    switch (bankName) {
      case "KB국민은행": // 123456-78-901234 (14자리)
        const kb = numbers.slice(0, 14);
        if (kb.length <= 6) return kb;
        if (kb.length <= 8) return `${kb.slice(0, 6)}-${kb.slice(6)}`;
        return `${kb.slice(0, 6)}-${kb.slice(6, 8)}-${kb.slice(8)}`;

      case "신한은행": // 110-123-456789 (12자리)
        const sh = numbers.slice(0, 12);
        if (sh.length <= 3) return sh;
        if (sh.length <= 6) return `${sh.slice(0, 3)}-${sh.slice(3)}`;
        return `${sh.slice(0, 3)}-${sh.slice(3, 6)}-${sh.slice(6)}`;

      case "우리은행": // 1002-123-456789 (13자리)
        const wr = numbers.slice(0, 13);
        if (wr.length <= 4) return wr;
        if (wr.length <= 7) return `${wr.slice(0, 4)}-${wr.slice(4)}`;
        return `${wr.slice(0, 4)}-${wr.slice(4, 7)}-${wr.slice(7)}`;

      case "하나은행": // 123-456789-01234 (14자리)
        const hn = numbers.slice(0, 14);
        if (hn.length <= 3) return hn;
        if (hn.length <= 9) return `${hn.slice(0, 3)}-${hn.slice(3)}`;
        return `${hn.slice(0, 3)}-${hn.slice(3, 9)}-${hn.slice(9)}`;

      case "NH농협은행": // 123-4567-8901-23 (13자리)
        const nh = numbers.slice(0, 13);
        if (nh.length <= 3) return nh;
        if (nh.length <= 7) return `${nh.slice(0, 3)}-${nh.slice(3)}`;
        if (nh.length <= 11) return `${nh.slice(0, 3)}-${nh.slice(3, 7)}-${nh.slice(7)}`;
        return `${nh.slice(0, 3)}-${nh.slice(3, 7)}-${nh.slice(7, 11)}-${nh.slice(11)}`;

      case "IBK기업은행": // 123-456789-12-345 (14자리)
        const ibk = numbers.slice(0, 14);
        if (ibk.length <= 3) return ibk;
        if (ibk.length <= 9) return `${ibk.slice(0, 3)}-${ibk.slice(3)}`;
        if (ibk.length <= 11) return `${ibk.slice(0, 3)}-${ibk.slice(3, 9)}-${ibk.slice(9)}`;
        return `${ibk.slice(0, 3)}-${ibk.slice(3, 9)}-${ibk.slice(9, 11)}-${ibk.slice(11)}`;

      case "SC제일은행": // 123-45-678901 (11자리)
        const sc = numbers.slice(0, 11);
        if (sc.length <= 3) return sc;
        if (sc.length <= 5) return `${sc.slice(0, 3)}-${sc.slice(3)}`;
        return `${sc.slice(0, 3)}-${sc.slice(3, 5)}-${sc.slice(5)}`;

      case "카카오뱅크": // 3333-12-3456789 (13자리)
        const kakao = numbers.slice(0, 13);
        if (kakao.length <= 4) return kakao;
        if (kakao.length <= 6) return `${kakao.slice(0, 4)}-${kakao.slice(4)}`;
        return `${kakao.slice(0, 4)}-${kakao.slice(4, 6)}-${kakao.slice(6)}`;

      case "토스뱅크": // 1234-5678-9012 (12자리)
        const toss = numbers.slice(0, 12);
        if (toss.length <= 4) return toss;
        if (toss.length <= 8) return `${toss.slice(0, 4)}-${toss.slice(4)}`;
        return `${toss.slice(0, 4)}-${toss.slice(4, 8)}-${toss.slice(8)}`;

      case "케이뱅크": // 123-456-789012 (12자리)
        const k = numbers.slice(0, 12);
        if (k.length <= 3) return k;
        if (k.length <= 6) return `${k.slice(0, 3)}-${k.slice(3)}`;
        return `${k.slice(0, 3)}-${k.slice(3, 6)}-${k.slice(6)}`;

      default:
        return numbers;
    }
  };

  const handleBankAccountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const formatted = formatBankAccount(e.target.value, formData.bank_name);
    setFormData({ ...formData, bank_account: formatted });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!authUser || !formData.area) return;

    setLoading(true);

    try {
      const slug = generateSlug(formData.name);

      const { error } = await supabase.from("users").insert({
        id: authUser.id,
        kakao_id: authUser.user_metadata?.provider_id || authUser.id,
        name: formData.name,
        phone: formData.phone,
        profile_image: authUser.user_metadata?.avatar_url || null,
        role: "user", // Admin 승인 후 'md'로 변경
        md_status: "pending",
        md_unique_slug: slug,
        bank_name: formData.bank_name,
        bank_account: formData.bank_account,
      });

      if (error) throw error;

      toast.success("MD 신청이 완료되었습니다! 승인을 기다려주세요.");
      router.push("/");
    } catch (error: any) {
      console.error("MD signup error:", error);
      toast.error(error.message || "신청 중 오류가 발생했습니다");
    } finally {
      setLoading(false);
    }
  };

  if (!authUser) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p>로딩 중...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-b from-neutral-950 to-neutral-900 p-4">
      <Card className="w-full max-w-md p-8 space-y-6">
        <div className="text-center space-y-2">
          <h1 className="text-2xl font-bold">MD 신청</h1>
          <p className="text-sm text-neutral-500">
            클럽 테이블 경매를 등록하고 수수료를 받으세요
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="name">이름 *</Label>
            <Input
              id="name"
              value={formData.name}
              onChange={(e) =>
                setFormData({ ...formData, name: e.target.value })
              }
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="phone">전화번호 *</Label>
            <Input
              id="phone"
              type="tel"
              value={formData.phone}
              onChange={(e) =>
                setFormData({ ...formData, phone: e.target.value })
              }
              placeholder="010-1234-5678"
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="area">활동 지역 *</Label>
            <select
              id="area"
              value={formData.area}
              onChange={(e) =>
                setFormData({ ...formData, area: e.target.value as Area })
              }
              className="w-full px-3 py-2 bg-white text-black border border-neutral-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
              required
            >
              <option value="">선택하세요</option>
              <option value="강남">강남</option>
              <option value="홍대">홍대</option>
              <option value="이태원">이태원</option>
            </select>
          </div>

          <div className="space-y-2">
            <Label htmlFor="bank_name">정산 은행 *</Label>
            <select
              id="bank_name"
              value={formData.bank_name}
              onChange={(e) =>
                setFormData({ ...formData, bank_name: e.target.value })
              }
              className="w-full px-3 py-2 bg-white text-black border border-neutral-300 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500"
              required
            >
              <option value="">선택하세요</option>
              <option value="KB국민은행">KB국민은행</option>
              <option value="신한은행">신한은행</option>
              <option value="우리은행">우리은행</option>
              <option value="하나은행">하나은행</option>
              <option value="NH농협은행">NH농협은행</option>
              <option value="IBK기업은행">IBK기업은행</option>
              <option value="SC제일은행">SC제일은행</option>
              <option value="카카오뱅크">카카오뱅크</option>
              <option value="토스뱅크">토스뱅크</option>
              <option value="케이뱅크">케이뱅크</option>
            </select>
          </div>

          <div className="space-y-2">
            <Label htmlFor="bank_account">계좌번호 *</Label>
            <Input
              id="bank_account"
              value={formData.bank_account}
              onChange={handleBankAccountChange}
              placeholder={
                formData.bank_name === "KB국민은행"
                  ? "123456-78-901234"
                  : formData.bank_name === "신한은행"
                  ? "110-123-456789"
                  : formData.bank_name === "우리은행"
                  ? "1002-123-456789"
                  : formData.bank_name === "하나은행"
                  ? "123-456789-01234"
                  : formData.bank_name === "NH농협은행"
                  ? "123-4567-8901-23"
                  : formData.bank_name === "IBK기업은행"
                  ? "123-456789-12-345"
                  : formData.bank_name === "SC제일은행"
                  ? "123-45-678901"
                  : formData.bank_name === "카카오뱅크"
                  ? "3333-12-3456789"
                  : formData.bank_name === "토스뱅크"
                  ? "1234-5678-9012"
                  : formData.bank_name === "케이뱅크"
                  ? "123-456-789012"
                  : "계좌번호를 입력하세요"
              }
              required
            />
          </div>

          <div className="bg-neutral-900 p-4 rounded-md text-sm text-neutral-400">
            <p>• MD 승인은 최대 1-2일 소요됩니다</p>
            <p>• 승인 후 경매 등록이 가능합니다</p>
            <p>• 낙찰가의 10% 수수료를 받게 됩니다</p>
          </div>

          <Button type="submit" className="w-full" disabled={loading}>
            {loading ? "신청 중..." : "MD 신청하기"}
          </Button>
        </form>
      </Card>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card } from "@/components/ui/card";
import { toast } from "sonner";

export default function SignupPage() {
  const router = useRouter();
  const supabase = createClient();
  const [loading, setLoading] = useState(false);
  const [authUser, setAuthUser] = useState<any>(null);
  const [formData, setFormData] = useState({
    name: "",
    phone: "",
  });

  useEffect(() => {
    // 카카오 로그인 후 auth user 가져오기
    supabase.auth.getUser().then(({ data: { user } }) => {
      if (!user) {
        router.push("/login");
        return;
      }
      setAuthUser(user);
      // 카카오 프로필에서 이름 가져오기
      const kakaoName =
        user.user_metadata?.full_name || user.user_metadata?.name || "";
      setFormData((prev) => ({ ...prev, name: kakaoName }));
    });
  }, [router, supabase]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!authUser) return;

    setLoading(true);

    try {
      // users 테이블에 프로필 생성
      const { error } = await supabase.from("users").insert({
        id: authUser.id,
        kakao_id: authUser.user_metadata?.provider_id || authUser.id,
        name: formData.name,
        phone: formData.phone,
        profile_image: authUser.user_metadata?.avatar_url || null,
        role: "user",
      });

      if (error) throw error;

      toast.success("가입이 완료되었습니다!");
      router.push("/");
    } catch (error: any) {
      console.error("Signup error:", error);
      toast.error(error.message || "가입 중 오류가 발생했습니다");
    } finally {
      setLoading(false);
    }
  };

  if (!authUser) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p>로딩 중...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-b from-neutral-950 to-neutral-900 p-4">
      <Card className="w-full max-w-md p-8 space-y-6">
        <div className="text-center space-y-2">
          <h1 className="text-2xl font-bold">프로필 설정</h1>
          <p className="text-sm text-neutral-500">
            NightFlow에 오신 것을 환영합니다!
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="name">이름 *</Label>
            <Input
              id="name"
              value={formData.name}
              onChange={(e) =>
                setFormData({ ...formData, name: e.target.value })
              }
              placeholder="홍길동"
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="phone">전화번호 *</Label>
            <Input
              id="phone"
              type="tel"
              value={formData.phone}
              onChange={(e) =>
                setFormData({ ...formData, phone: e.target.value })
              }
              placeholder="010-1234-5678"
              required
            />
          </div>

          <Button type="submit" className="w-full" disabled={loading}>
            {loading ? "가입 중..." : "시작하기"}
          </Button>

          <div className="text-center">
            <button
              type="button"
              onClick={() => router.push("/signup/md")}
              className="text-sm text-neutral-400 hover:text-neutral-200 underline"
            >
              MD로 활동하고 싶으신가요?
            </button>
          </div>
        </form>
      </Card>
    </div>
  );
}

import { redirect } from "next/navigation";
import { createClient } from "@/lib/supabase/server";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { formatPrice, formatDate } from "@/lib/utils/format";
import { Gavel, CreditCard, Clock, CheckCircle2, ChevronRight } from "lucide-react";
import Link from "next/link";

export default async function AdminAuctionsPage() {
    const supabase = await createClient();

    // 1. 관리자 권한 확인
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) redirect("/login");

    const { data: userData } = await supabase
        .from("users")
        .select("role")
        .eq("id", user.id)
        .single();

    if (userData?.role !== "admin") {
        // redirect("/");
    }

    // 2. 경매 목록 및 통계 데이터 조회 (Club, MD 정보 포함)
    const { data: auctions } = await supabase
        .from("auctions")
        .select(`
      *,
      club:club_id (*),
      md:md_id (name)
    `)
        .order("created_at", { ascending: false });

    const activeCount = auctions?.filter(a => a.status === "active").length || 0;
    const pendingPaymentCount = auctions?.filter(a => a.status === "won").length || 0;
    const paidCount = auctions?.filter(a => a.status === "paid").length || 0;

    return (
        <div className="min-h-screen bg-[#0A0A0A] text-white pt-12 pb-24">
            <div className="max-w-6xl mx-auto px-6 space-y-10">
                {/* Header */}
                <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                    <div className="space-y-2">
                        <div className="flex items-center gap-2 text-neutral-500 font-bold uppercase tracking-widest text-[11px]">
                            <Gavel className="w-3.5 h-3.5" />
                            Live Marketplace Ops
                        </div>
                        <h1 className="text-4xl font-black tracking-tighter">전체 경매 현황</h1>
                        <p className="text-neutral-500 font-medium">실시간으로 진행되는 모든 경매와 결제 성사 내역을 모니터링합니다.</p>
                    </div>

                    <div className="flex gap-4">
                        <Card className="bg-[#1C1C1E] border-neutral-800 p-4 flex flex-col gap-1 min-w-[120px]">
                            <div className="flex items-center gap-2 text-neutral-500">
                                <Gavel className="w-4 h-4" />
                                <span className="text-[10px] font-bold uppercase tracking-tight">활성 경매</span>
                            </div>
                            <p className="text-2xl font-black text-white">{activeCount}</p>
                        </Card>
                        <Card className="bg-[#1C1C1E] border-neutral-800 p-4 flex flex-col gap-1 min-w-[120px] shadow-[0_0_20px_rgba(34,197,94,0.1)]">
                            <div className="flex items-center gap-2 text-green-500">
                                <CreditCard className="w-4 h-4" />
                                <span className="text-[10px] font-bold uppercase tracking-tight">결제 완료</span>
                            </div>
                            <p className="text-2xl font-black text-white">{paidCount}</p>
                        </Card>
                    </div>
                </header>

                {/* List View */}
                <div className="space-y-4">
                    <div className="grid grid-cols-12 px-6 py-2 text-[10px] text-neutral-500 font-black uppercase tracking-widest border-b border-neutral-800">
                        <div className="col-span-4">Auction Item / MD</div>
                        <div className="col-span-2 text-center">Status</div>
                        <div className="col-span-3 text-right">Price / Bids</div>
                        <div className="col-span-3 text-right">Date</div>
                    </div>

                    {auctions && auctions.length > 0 ? (
                        auctions.map((a) => (
                            <Link key={a.id} href={`/auctions/${a.id}`} className="block">
                                <Card className="bg-[#1C1C1E] border-neutral-800/50 hover:border-neutral-700 transition-all group p-5">
                                    <div className="grid grid-cols-12 items-center gap-4">
                                        {/* Item Info */}
                                        <div className="col-span-4 flex items-center gap-4">
                                            <div className="w-12 h-12 rounded-xl bg-neutral-900 border border-neutral-800 flex items-center justify-center font-black text-neutral-600">
                                                {a.club?.name?.substring(0, 1) || "C"}
                                            </div>
                                            <div>
                                                <p className="text-white font-bold">{a.club?.name} {a.table_type}</p>
                                                <p className="text-[12px] text-neutral-500 font-medium">MD: {a.md?.name || "Shared"}</p>
                                            </div>
                                        </div>

                                        {/* Status */}
                                        <div className="col-span-2 flex justify-center">
                                            <Badge className={`${a.status === 'paid' ? 'bg-green-500/10 text-green-500 border-green-500/20' :
                                                    a.status === 'active' ? 'bg-red-500/10 text-red-500 border-red-500/20' :
                                                        a.status === 'won' ? 'bg-amber-500/10 text-amber-500 border-amber-500/20' :
                                                            'bg-neutral-800 text-neutral-500 border-neutral-700'
