export default async function PaymentSuccessPage({
    searchParams,
}: {
    searchParams: Promise<{ auctionId: string; paymentKey: string; orderId: string; amount: string }>;
}) {
    const { auctionId, paymentKey, orderId, amount } = await searchParams;
    const supabase = await createClient();

    if (!auctionId || !paymentKey) {
        redirect("/");
    }

    // 1. 세션 확인
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) redirect("/login");

    // 2. 결제 검증 (Verify with Toss API)
    try {
        // 검증 전: 경매 데이터와 낙찰 기한 확인
        const { data: auctionCheck } = await supabase
            .from("auctions")
            .select("payment_deadline, status")
            .eq("id", auctionId)
            .single();

        if (auctionCheck?.status !== "won") {
            throw new Error("결제 가능한 상태가 아닙니다.");
        }

        const now = new Date();
        const deadline = new Date(auctionCheck.payment_deadline);
        if (now > deadline) {
            throw new Error("결제 시간이 만료되었습니다. (15분 초과)");
        }

        await confirmTossPayment(paymentKey, orderId, parseInt(amount));

        // 3. 결제 완료 상태로 업데이트
        const { data: auction, error } = await supabase
            .from("auctions")
            .update({
                status: "paid",
            })
            .eq("id", auctionId)
            .eq("winner_id", user.id)
            .select(`
                *,
                club:club_id (*)
            `)
            .single();

        if (error) throw error;

        // 4. 트랜잭션 수동 업데이트
        await supabase
            .from("transactions")
            .update({
                payment_key: paymentKey,
                payment_status: "paid",
                paid_at: new Date().toISOString()
            })
            .eq("auction_id", auctionId)
            .eq("buyer_id", user.id);

    } catch (error: any) {
        console.error("Payment verification failed:", error);
        // 결제 실패 또는 검증 오류 시 실패 페이지로 이동하거나 에러 표시
        redirect(`/checkout/fail?message=${encodeURIComponent(error.message)}`);
    }

    const { data: displayAuction } = await supabase
        .from("auctions")
        .select("*, club:club_id(*)")
        .eq("id", auctionId)
        .single();

    if (!displayAuction) redirect("/my-wins");

    return (
        <div className="min-h-screen bg-[#0A0A0A] flex flex-col items-center justify-center px-4 py-20">
            <div className="max-w-md w-full space-y-10 text-center">
                {/* Success Icon Animation Wrap */}
                <div className="relative inline-block">
                    <div className="w-24 h-24 bg-green-500/20 rounded-full flex items-center justify-center mx-auto border border-green-500/30">
                        <CheckCircle2 className="w-12 h-12 text-green-500" />
                    </div>
                    <PartyPopper className="absolute -top-2 -right-2 w-8 h-8 text-amber-500" />
                </div>

                <div className="space-y-3">
                    <h1 className="text-4xl font-black text-white tracking-tighter">예약이 확정되었습니다!</h1>
                    <p className="text-neutral-500 font-medium">결제가 안전하게 완료되었습니다.<br />담당 MD가 곧 확정 안내를 드릴 예정입니다.</p>
                </div>

                <Card className="bg-[#1C1C1E] border-neutral-800 p-6 text-left space-y-4 shadow-[0_0_50px_rgba(34,197,94,0.1)]">
                    <div className="space-y-1">
                        <p className="text-[10px] text-neutral-500 font-black uppercase tracking-widest">Reserved Club</p>
                        <h2 className="text-xl font-black text-white">{displayAuction?.club?.name} {displayAuction?.table_type}</h2>
                    </div>

                    <div className="h-px bg-neutral-800/50" />

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                            <div className="flex items-center gap-1 text-[10px] text-neutral-500 font-bold uppercase">
                                <Calendar className="w-3 h-3" /> Visit Date
                            </div>
                            <p className="text-white font-bold text-sm">{formatDate(displayAuction?.event_date)}</p>
                        </div>
                        <div className="space-y-1">
                            <div className="flex items-center gap-1 text-[10px] text-neutral-500 font-bold uppercase">
                                <MapPin className="w-3 h-3" /> Area
                            </div>
                            <p className="text-white font-bold text-sm">{displayAuction?.club?.area}</p>
                        </div>
                    </div>
                </Card>

                <div className="space-y-3 pt-6">
                    <Link href="/my-wins" className="block w-full">
                        <Button className="w-full h-14 bg-white text-black font-black text-lg hover:bg-neutral-200 rounded-2xl shadow-xl">
