import { createClient } from "@/lib/supabase/server";
import { NextResponse } from "next/server";
import crypto from "crypto";

const TOSS_WEBHOOK_SECRET = process.env.TOSS_WEBHOOK_SECRET;

export async function POST(req: Request) {
    try {
        // 1. 서명 검증 (Security Improvement)
        const signature = req.headers.get("x-toss-webhook-signature");
        const rawBody = await req.text();

        if (!TOSS_WEBHOOK_SECRET) {
            console.error("TOSS_WEBHOOK_SECRET is not configured");
            return NextResponse.json({ error: "Server configuration error" }, { status: 500 });
        }

        const expectedSignature = crypto
            .createHmac("sha256", TOSS_WEBHOOK_SECRET)
            .update(rawBody)
            .digest("hex");

        if (signature !== expectedSignature) {
            console.warn("Invalid webhook signature detected");
            return NextResponse.json({ error: "Invalid signature" }, { status: 401 });
        }

        const body = JSON.parse(rawBody);
        const { eventType, data } = body;

        // Toss Webhook event types: PAYMENTS_CONFIRMED, PAYMENTS_CANCELED, etc.
        if (eventType === "PAYMENT_CONFIRMATION_DONE") {
            const { orderId, paymentKey } = data;
            const auctionId = orderId.split("_")[1];

            const supabase = await createClient();

            // 1. Transaction 조회
            const { data: transaction } = await supabase
                .from("transactions")
                .select("*")
                .eq("payment_key", paymentKey)
                .single();

            if (transaction && transaction.payment_status === "paid") {
                return NextResponse.json({ message: "Already processed" });
            }

            // 2. 상태 업데이트
            await supabase
                .from("auctions")
                .update({ status: "paid" })
                .eq("id", auctionId);

            await supabase
                .from("transactions")
                .update({
                    payment_status: "paid",
                    paid_at: new Date().toISOString()
                })
                .eq("payment_key", paymentKey);
        }

        return NextResponse.json({ success: true });
    } catch (error: any) {
        console.error("Webhook error:", error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

