export function MDManagement({ initialUsers }: { initialUsers: User[] }) {
    const [users, setUsers] = useState<User[]>(initialUsers);
    const [loadingId, setLoadingId] = useState<string | null>(null);
    const supabase = createClient();

    const pendingUsers = users.filter(u => u.md_status === "pending");
    const approvedUsers = users.filter(u => u.md_status === "approved");
    const rejectedUsers = users.filter(u => u.md_status === "rejected");

    const handleStatusUpdate = async (userId: string, status: "approved" | "rejected") => {
        setLoadingId(userId);
        try {
            const updateData: any = { md_status: status };
            if (status === "approved") {
                updateData.role = "md";
            }

            const { error } = await supabase
                .from("users")
                .update(updateData)
                .eq("id", userId);

            if (error) throw error;

            toast.success(status === "approved" ? "MD 승인이 완료되었습니다!" : "반려 처리되었습니다.");

            // 상태 업데이트 (UI 반영)
            setUsers(prev => prev.map(u =>
                u.id === userId ? { ...u, md_status: status, role: status === "approved" ? "md" : u.role } : u
            ));
        } catch (error: any) {
            toast.error(error.message || "작업 중 오류가 발생했습니다.");
        } finally {
            setLoadingId(null);
        }
    };

    return (
        <div className="space-y-6">
            <Tabs defaultValue="pending" className="w-full">
                <TabsList className="bg-neutral-900 border border-neutral-800 p-1 h-12 rounded-xl">
                    <TabsTrigger value="pending" className="flex-1 rounded-lg font-bold data-[state=active]:bg-[#1C1C1E] data-[state=active]:text-white">
                        심사 대기 ({pendingUsers.length})
                    </TabsTrigger>
                    <TabsTrigger value="approved" className="flex-1 rounded-lg font-bold data-[state=active]:bg-[#1C1C1E] data-[state=active]:text-white">
                        활동 중 ({approvedUsers.length})
                    </TabsTrigger>
                    <TabsTrigger value="rejected" className="flex-1 rounded-lg font-bold data-[state=active]:bg-[#1C1C1E] data-[state=active]:text-white">
                        반려 내역 ({rejectedUsers.length})
                    </TabsTrigger>
                </TabsList>

                <div className="mt-8">
                    <TabsContent value="pending" className="m-0 space-y-4">
                        {pendingUsers.length > 0 ? (
                            pendingUsers.map(u => (
                                <MDApplicationCard
                                    key={u.id}
                                    user={u}
                                    onAction={(status) => handleStatusUpdate(u.id, status)}
                                    loading={loadingId === u.id}
                                />
                            ))
                        ) : (
                            <EmptyAdminState label="심사 대기 명단이 없습니다." />
                        )}
                    </TabsContent>

                    <TabsContent value="approved" className="m-0 space-y-4">
                        {approvedUsers.map(u => (
                            <MDApplicationCard key={u.id} user={u} isSimple />
                        ))}
                    </TabsContent>

                    <TabsContent value="rejected" className="m-0 space-y-4">
                        {rejectedUsers.map(u => (
                            <MDApplicationCard key={u.id} user={u} isSimple />
                        ))}
                    </TabsContent>
                </div>
            </Tabs>
        </div>
    );
}

