      )}
      {/* 8. Winner Payment CTA (Bottom) */}
      {needsPayment && (
        <div className="bg-[#0A0A0A]/95 backdrop-blur-xl border-t border-red-500/20 p-4 sticky bottom-0 z-[60] animate-in slide-in-from-bottom duration-500">
          <div className="max-w-lg mx-auto space-y-3">
            <div className="flex items-center justify-between px-1">
              <div className="flex items-center gap-2">
                <PartyPopper className="w-5 h-5 text-amber-500" />
                <span className="text-white font-black text-lg">축하드립니다! 낙찰되셨습니다.</span>
              </div>
            </div>
            <p className="text-neutral-400 text-[11px] font-medium px-1">
              15분 내에 결제가 완료되지 않으면 낙찰이 취소되며 노쇼 패널티가 부과될 수 있습니다.
            </p>
            <Button
              onClick={() => router.push(`/checkout/${displayAuction.id}`)}
              className="w-full h-14 bg-red-600 hover:bg-red-700 text-white font-black text-lg rounded-2xl shadow-[0_0_20px_rgba(220,38,38,0.3)] transition-all active:scale-[0.98]"
            >
              지금 바로 결제하기
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import type { Bid } from "@/types/database";
