"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card } from "@/components/ui/card";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from "@/components/ui/sheet";
import { toast } from "sonner";
import { createClient } from "@/lib/supabase/client";
import { useCurrentUser } from "@/hooks/useCurrentUser";
import type { Auction } from "@/types/database";
import { formatPrice } from "@/lib/utils/format";
import { getMinBidAmount, getBidPresets, isAuctionActive, isAuctionExpired } from "@/lib/utils/auction";

interface BidPanelProps {
  auction: Auction;
  onBidSuccess: () => void;
}

export function BidPanel({ auction, onBidSuccess }: BidPanelProps) {
  const { user } = useCurrentUser();
  const supabase = createClient();
  const [bidAmount, setBidAmount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const isActive = isAuctionActive(auction);
  const isExpired = isAuctionExpired(auction);
  const minBid = getMinBidAmount(auction);
  const presets = getBidPresets(auction);

  const handlePresetClick = (amount: number) => {
    setBidAmount(amount);
  };

  const handleBidSubmit = async () => {
    if (!user) {
      toast.error("로그인이 필요합니다");
      return;
    }

    if (bidAmount < minBid) {
      toast.error(`최소 입찰가는 ${formatPrice(minBid)}입니다`);
      return;
    }

    setLoading(true);

    try {
      const { data, error } = await supabase.rpc("place_bid", {
        p_auction_id: auction.id,
        p_bidder_id: user.id,
        p_bid_amount: bidAmount,
      });

      if (error) throw error;

      toast.success("입찰이 완료되었습니다! 🎉");
      setShowConfirm(false);
      setBidAmount(0);
      onBidSuccess();
    } catch (error: any) {
      console.error("Bid error:", error);
      toast.error(error.message || "입찰 중 오류가 발생했습니다");
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <Card className="p-3 space-y-2.5 bg-[#1C1C1E] border-neutral-800/50">
        <div className="space-y-1">
          <p className="text-[10px] text-neutral-500 font-bold uppercase tracking-wider ml-1">빠른 입찰</p>
          <div className="grid grid-cols-4 gap-2">
            {presets.map((amount) => {
              const diff = amount - (auction.current_bid || auction.start_price);
              const label = diff === 0 ? "최소" : `+${diff / 10000}만`;
              return (
                <Button
                  key={amount}
                  variant={bidAmount === amount ? "default" : "outline"}
                  onClick={() => handlePresetClick(amount)}
                  className={`text-[12px] h-9 border-neutral-800 font-bold ${bidAmount === amount ? "bg-white text-black hover:bg-neutral-200" : "bg-neutral-900/50 text-neutral-400"
                    }`}
                >
                  {label}
                </Button>
              );
            })}
          </div>
        </div>

        <div className="space-y-1">
          <p className="text-[10px] text-neutral-500 font-bold uppercase tracking-wider ml-1">직접 입력</p>
          <Input
            type="number"
            placeholder={`최소 ${formatPrice(minBid)}`}
            value={bidAmount || ""}
            onChange={(e) => setBidAmount(parseInt(e.target.value) || 0)}
            min={minBid}
            step={auction.bid_increment}
            className="bg-neutral-900/80 border-neutral-800 h-11 text-white font-bold focus:ring-green-500 text-sm"
          />
        </div>

        <div className="bg-neutral-900/30 rounded-lg p-2 border border-neutral-800/20">
          <div className="flex justify-between text-sm">
            <span className="text-neutral-400">내 입찰가</span>
            <span className="font-bold text-green-500">
              {bidAmount > 0 ? formatPrice(bidAmount) : "-"}
            </span>
          </div>
        </div>

        <Button
          className="w-full h-11 text-base font-black bg-white text-black hover:bg-neutral-200 rounded-xl shadow-xl transition-all active:scale-[0.98]"
          onClick={() => setShowConfirm(true)}
          disabled={!isActive || bidAmount < minBid || loading}
        >
          {!isActive ? (isExpired ? "마감되었습니다" : "경매 종료") : bidAmount > 0 ? `${formatPrice(bidAmount)}으로 입찰하기` : "금액을 입력하세요"}
        </Button>
      </Card>

      {/* 확인 시트 */}
      <Sheet open={showConfirm} onOpenChange={setShowConfirm}>
        <SheetContent side="bottom" className="h-auto bg-[#1C1C1E] border-neutral-800 rounded-t-3xl">
          <SheetHeader className="text-left">
            <SheetTitle className="text-white font-black text-xl">입찰 확인</SheetTitle>
            <SheetDescription className="text-neutral-400">
              {formatPrice(bidAmount)}으로 입찰하시겠습니까?
            </SheetDescription>
          </SheetHeader>
          <div className="space-y-4 mt-6">
            <div className="bg-neutral-900/50 rounded-2xl p-4 space-y-3 border border-neutral-800/50">
              <div className="flex justify-between items-center">
                <span className="text-neutral-500 text-sm font-bold">경매 상품</span>
                <span className="font-bold text-white">{auction.title}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-neutral-500 text-sm font-bold">최종 입찰가</span>
                <span className="font-black text-2xl text-green-500">
                  {formatPrice(bidAmount)}
                </span>
              </div>
            </div>

            <div className="bg-red-500/10 border border-red-500/20 rounded-xl p-4 text-[13px] text-red-400 font-medium leading-relaxed">
              ⚠️ 낙찰 시 15분 내 결제가 필요하며, 미결제 시 이용 제한 등의 불이익이 발생할 수 있습니다.
            </div>

            <div className="grid grid-cols-2 gap-3 pb-8">
              <Button
                variant="outline"
                onClick={() => setShowConfirm(false)}
                className="h-14 rounded-2xl border-neutral-800 text-neutral-400 font-bold"
              >
                취소
              </Button>
              <Button
                onClick={handleBidSubmit}
                disabled={loading}
                className="h-14 rounded-2xl bg-white text-black font-black text-lg hover:bg-neutral-200"
              >
                {loading ? "입찰 중..." : "확인"}
              </Button>
            </div>
          </div>
        </SheetContent>
      </Sheet>
    </>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { loadPaymentWidget, PaymentWidgetInstance } from "@tosspayments/payment-widget-sdk";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { formatPrice } from "@/lib/utils/format";
import { Loader2, ShieldCheck, CreditCard, Timer, AlertTriangle } from "lucide-react";
import type { Auction } from "@/types/database";
import { useCountdown } from "@/hooks/useCountdown";
import dayjs from "dayjs";
import type { User } from "@/types/database";

const clientKey = process.env.NEXT_PUBLIC_TOSS_CLIENT_KEY;

if (!clientKey) {
    throw new Error("NEXT_PUBLIC_TOSS_CLIENT_KEY is not configured");
}

interface CheckoutClientProps {
    auction: Auction;
    user: User;
}

export function CheckoutClient({ auction, user }: CheckoutClientProps) {
    const [paymentWidget, setPaymentWidget] = useState<PaymentWidgetInstance | null>(null);
    const [loading, setLoading] = useState(true);

    const remaining = useCountdown(auction.payment_deadline);
    const isExpired = remaining <= 0;

    const formatRemaining = (seconds: number) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins.toString().padStart(2, "0")}:${secs.toString().padStart(2, "0")}`;
    };

    useEffect(() => {
        const fetchPaymentWidget = async () => {
            try {
                const widget = await loadPaymentWidget(clientKey!, user.id);

                // 결제 금액 설정
                widget.renderPaymentMethods(
                    "#payment-method",
                    { value: auction.current_bid },
                    { variantKey: "DEFAULT" }
                );

                // 이용약관 렌더링
                widget.renderAgreement("#agreement", { variantKey: "AGREEMENT" });

                setPaymentWidget(widget);
            } catch (error) {
                console.error("Error loading payment widget:", error);
            } finally {
                setLoading(false);
            }
        };

        fetchPaymentWidget();
    }, [auction.current_bid, user.id]);

    const handlePayment = async () => {
        if (!paymentWidget) return;

        try {
            await paymentWidget.requestPayment({
                orderId: `NF_${auction.id.slice(0, 8)}_${Date.now()}`,
                orderName: `NightFlow - ${auction.club?.name} ${auction.table_type}`,
                customerName: user.name || "고객",
                successUrl: `${window.location.origin}/checkout/success?auctionId=${auction.id}`,
                failUrl: `${window.location.origin}/checkout/fail`,
            });
        } catch (error) {
            console.error("Payment request failed:", error);
        }
    };

    return (
        <div className="space-y-6">
            {/* Payment Deadline Countdown */}
            <div className={`p-4 rounded-xl border flex items-center justify-between animate-pulse ${isExpired ? "bg-red-500/10 border-red-500/50 text-red-500" : "bg-amber-500/10 border-amber-500/50 text-amber-500"
                }`}>
                <div className="flex items-center gap-2">
                    <Timer className="w-5 h-5" />
                    <span className="text-sm font-black uppercase tracking-tight">결제 대기 시간</span>
                </div>
                <span className="text-xl font-black tabular-nums">{formatRemaining(remaining)}</span>
            </div>

            <Card className="bg-[#1C1C1E] border-neutral-800 p-6 space-y-4 shadow-2xl">
                <div className="space-y-1">
                    <p className="text-[11px] text-neutral-500 font-bold uppercase tracking-widest">최종 결제 금액</p>
                    <p className="text-4xl font-black text-white tracking-tighter">{formatPrice(auction.current_bid)}</p>
                </div>

                <div className="h-px bg-neutral-800/50" />

                <div className="space-y-2">
                    <div className="flex justify-between items-center text-sm">
                        <span className="text-neutral-500 font-medium tracking-tight">경매 정보</span>
                        <span className="text-white font-bold">{auction.club?.name} {auction.table_type}</span>
                    </div>
                    <div className="flex justify-between items-center text-sm">
                        <span className="text-neutral-500 font-medium tracking-tight">방문 날짜</span>
                        <span className="text-white font-bold">{auction.event_date}</span>
                    </div>
                </div>
            </Card>

            {isExpired && (
                <div className="bg-red-500/10 border border-red-500/20 rounded-xl p-4 flex items-start gap-3">
                    <AlertTriangle className="w-5 h-5 text-red-500 flex-shrink-0 mt-0.5" />
                    <div className="space-y-1">
                        <p className="text-sm font-bold text-red-500">결제 시간이 만료되었습니다.</p>
                        <p className="text-xs text-red-500/70 font-medium">낙찰이 취소되었을 수 있습니다. 마이페이지에서 확인해주세요.</p>
                    </div>
                </div>
            )}

            {/* Toss Widget Containers */}
            <div className="space-y-2">
                <div id="payment-method" className="min-h-[300px]" />
                <div id="agreement" />
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-4 bg-[#0A0A0A]/80 backdrop-blur-lg border-t border-neutral-800/50 z-50">
                <div className="max-w-lg mx-auto">
                    <Button
                        onClick={handlePayment}
                        disabled={loading || !paymentWidget || isExpired}
                        className={`w-full h-14 font-black text-lg rounded-2xl flex items-center justify-center gap-2 transition-all active:scale-[0.98] ${isExpired
                            ? "bg-neutral-800 text-neutral-500 cursor-not-allowed"
                            : "bg-white text-black hover:bg-neutral-200 shadow-[0_0_20px_rgba(255,255,255,0.15)]"
                            }`}
                    >
                        {loading ? (
                            <Loader2 className="w-5 h-5 animate-spin" />
                        ) : isExpired ? (
                            "결제 시간 만료"
                        ) : (
                            <>
                                <CreditCard className="w-5 h-5" />
                                {formatPrice(auction.current_bid)} 결제하기
                            </>
                        )}
                    </Button>
                    <div className="flex items-center justify-center gap-1.5 mt-3">
                        <ShieldCheck className="w-3.5 h-3.5 text-neutral-600" />
                        <span className="text-[11px] text-neutral-600 font-bold uppercase tracking-tighter leading-none">
                            Toss Payments Secure Checkout
                        </span>
                    </div>
                </div>
            </div>

            {/* Footer Bottom Spacer */}
            <div className="h-24" />
        </div>
    );
}

"use client";

import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card } from "@/components/ui/card";
import { toast } from "sonner";
import { createClient } from "@/lib/supabase/client";
import type { Club, TableType, Auction } from "@/types/database";
import { Calendar, Users, Wine, Check, ArrowRight } from "lucide-react";
import dayjs from "dayjs";

const formSchema = z.object({
    club_id: z.string().min(1, "클럽을 선택해주세요."),
    table_type: z.enum(["Standard", "VIP", "Premium"]),
    min_people: z.number().min(1),
    max_people: z.number().min(1),
    original_price: z.number().min(0, "정가를 입력해주세요."),
    start_price: z.number().min(0, "시작가를 입력해주세요."),
    event_date: z.string(),
    auction_start_at: z.string(),
    duration_minutes: z.number().min(1, "지속 시간을 선택해주세요."),
    includes: z.array(z.string()).min(1, "최소 한 개의 포함 내역을 선택해주세요."),
});

type FormValues = z.infer<typeof formSchema>;

interface AuctionFormProps {
    clubs: Club[];
    mdId: string;
    initialData?: Auction;
}

const COMMON_INCLUDES = ["기본 안주", "샴페인 1병", "샴페인 2병", "보드카 1병", "과일 안주", "음료 무제한"];

export function AuctionForm({ clubs, mdId, initialData }: AuctionFormProps) {
    const router = useRouter();
    const supabase = createClient();

    const { register, handleSubmit, setValue, watch, formState: { errors, isSubmitting } } = useForm<FormValues>({
        resolver: zodResolver(formSchema),
        defaultValues: {
            club_id: initialData?.club_id || "",
            table_type: (initialData?.table_type as TableType) || "Standard",
            min_people: initialData?.min_people || 2,
            max_people: initialData?.max_people || 4,
            duration_minutes: initialData?.duration_minutes || 60,
            includes: initialData?.includes || ["기본 안주"],
            event_date: initialData?.event_date || dayjs().add(1, "day").format("YYYY-MM-DD"),
            original_price: initialData?.original_price || 0,
            start_price: initialData?.start_price || 0,
            auction_start_at: initialData?.auction_start_at ? dayjs(initialData.auction_start_at).format("YYYY-MM-DDTHH:mm") : dayjs().format("YYYY-MM-DDTHH:mm"),
        }
    });

    const selectedIncludes = watch("includes");
    const selectedTableType = watch("table_type");

    const onSubmit = async (values: FormValues) => {
        try {
            const auction_start_at = new Date(values.auction_start_at).toISOString();
            const auction_end_at = dayjs(auction_start_at).add(values.duration_minutes, "minute").toISOString();

            const auctionData = {
                md_id: mdId,
                club_id: values.club_id,
                title: `${clubs.find(c => c.id === values.club_id)?.name} ${values.table_type} 테이블`,
                event_date: values.event_date,
                table_type: values.table_type,
                min_people: values.min_people,
                max_people: values.max_people,
                includes: values.includes,
                original_price: values.original_price,
                start_price: values.start_price,
                reserve_price: Math.floor(values.original_price * 0.6),
                auction_start_at,
                auction_end_at,
                duration_minutes: values.duration_minutes,
                status: initialData?.status || "scheduled",
                bid_increment: 10000,
            };

            const { error } = initialData
                ? await supabase.from("auctions").update(auctionData).eq("id", initialData.id)
                : await supabase.from("auctions").insert(auctionData);

            if (error) throw error;

            toast.success(initialData ? "경매 정보가 수정되었습니다!" : "경매가 성공적으로 등록 되었습니다!");
            router.push("/md/dashboard");
            router.refresh();
        } catch (error) {
            console.error(error);
            toast.error(initialData ? "경매 수정 중 오류가 발생했습니다." : "경매 등록 중 오류가 발생했습니다.");
        }
    };

    const toggleInclude = (item: string) => {
        const current = selectedIncludes;
        if (current.includes(item)) {
            setValue("includes", current.filter(i => i !== item));
        } else {
            setValue("includes", [...current, item]);
        }
    };

    return (
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-8 pb-12">
            {/* 1. 기본 정보 */}
            <section className="space-y-4">
                <div className="flex items-center gap-2 text-white font-bold mb-2">
                    <Calendar className="w-4 h-4 text-green-500" />
                    <span>기본 정보</span>
                </div>

                <div className="grid grid-cols-1 gap-4">
                    <div className="space-y-2">
                        <Label className="text-neutral-400 text-xs font-bold uppercase">클럽 선택</Label>
                        <select
                            {...register("club_id")}
                            className="w-full h-12 bg-[#1C1C1E] border border-neutral-800 rounded-xl px-4 text-white focus:outline-none focus:ring-1 focus:ring-green-500 appearance-none"
                        >
                            <option value="">클럽을 선택하세요</option>
                            {clubs.map(club => (
                                <option key={club.id} value={club.id}>{club.name} ({club.area})</option>
                            ))}
                        </select>
                        {errors.club_id && <p className="text-red-500 text-xs">{errors.club_id.message}</p>}
                    </div>

                    <div className="grid grid-cols-3 gap-2">
                        {["Standard", "VIP", "Premium"].map((type) => (
                            <button
                                key={type}
                                type="button"
                                onClick={() => setValue("table_type", type as TableType)}
                                className={`h-12 rounded-xl text-xs font-black transition-all ${selectedTableType === type
                                    ? "bg-white text-black"
