"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { CheckCircle2, Loader2 } from "lucide-react";
import { createClient } from "@/lib/supabase/client";
import { toast } from "sonner";
import { useRouter } from "next/navigation";

export function ConfirmVisitButton({ transactionId, auctionId }: { transactionId: string; auctionId: string }) {
    const [loading, setLoading] = useState(false);
    const supabase = createClient();
    const router = useRouter();

    const handleConfirm = async () => {
        if (!confirm("현장 방문을 확인하시겠습니까? 이 작업은 취소할 수 없습니다.")) return;

        setLoading(true);
        try {
            // 1. Transaction 상태 업데이트
            const { error: txError } = await supabase
                .from("transactions")
                .update({
                    payment_status: "paid", // 이미 paid이지만 명시적 확인용
                    confirmed_at: new Date().toISOString()
                })
                .eq("id", transactionId);

            if (txError) throw txError;

            // 2. Auction 상태 업데이트
            const { error: auctionError } = await supabase
                .from("auctions")
                .update({ status: "confirmed" })
                .eq("id", auctionId);

            if (auctionError) throw auctionError;

            toast.success("방문 확인이 완료되었습니다! 🎉");
            router.refresh();
        } catch (error: any) {
            console.error("Confirmation error:", error);
            toast.error(error.message || "확인 중 오류가 발생했습니다.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Button
            onClick={handleConfirm}
            disabled={loading}
            className="w-full h-12 bg-white text-black font-black hover:bg-neutral-200 rounded-xl flex items-center justify-center gap-2"
        >
            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <CheckCircle2 className="w-4 h-4" />}
            현장 방문 확인
        </Button>
    );
}

"use client";

