const formSchema = z.object({
    name: z.string().min(2, "실명을 입력해주세요"),
    phone: z.string().min(10, "올바른 연락처를 입력해주세요"),
    area: z.string().min(1, "활동 지역을 선택해주세요"),
    bank_name: z.string().min(2, "은행명을 입력해주세요"),
    bank_account: z.string().min(8, "계좌번호를 입력해주세요"),
    md_unique_slug: z.string().min(3, "최소 3자 이상의 아이디를 입력해주세요")
        .regex(/^[a-z0-9-]+$/, "영문 소문자, 숫자, 하이픈(-)만 가능합니다"),
});

type FormValues = z.infer<typeof formSchema>;

export function MDApplyForm({ initialUser }: { initialUser: User }) {
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const supabase = createClient();

    const form = useForm<FormValues>({
        resolver: zodResolver(formSchema),
        defaultValues: {
            name: initialUser.name || "",
            phone: initialUser.phone || "",
            area: "",
            bank_name: initialUser.bank_name || "",
            bank_account: initialUser.bank_account || "",
            md_unique_slug: initialUser.md_unique_slug || "",
        },
    });

    async function onSubmit(values: FormValues) {
        setLoading(true);
        try {
            const { error } = await supabase
                .from("users")
                .update({
                    ...values,
                    md_status: "pending",
                    // role은 어드민이 승인할 때 'md'로 변경합니다.
                })
                .eq("id", initialUser.id);

            if (error) throw error;

            toast.success("MD 파트너 신청이 완료되었습니다!");
            router.refresh(); // 상태 변경 반영을 위해 페이지 새로고침
