                                    {isActive ? "🔴 LIVE" : isExpired ? "마감중" : isScheduled ? "예정" : "종료"}
                                </Badge>
                                <span className="text-[11px] text-neutral-500">
                                    {auction.table_type} · {auction.min_people}-{auction.max_people}명
                                </span>
                            </div>
                            <h3 className="font-bold text-[16px] text-white truncate leading-tight">
                                {club?.name}
