"use client";

import { useState, useEffect, useRef } from "react";
import dayjs from "dayjs";

/** 카운트다운 훅: 남은 초를 반환 */
export function useCountdown(targetTime: string | null): number {
  const [remaining, setRemaining] = useState(() => {
    if (!targetTime) return 0;
    const target = dayjs(targetTime);
    return target.isValid() ? Math.max(0, target.diff(dayjs(), "second")) : 0;
  });

  useEffect(() => {
    const calculate = () => {
      if (!targetTime) {
        setRemaining(0);
        return;
      }
      const target = dayjs(targetTime);
      if (!target.isValid()) {
        setRemaining(0);
        return;
      }
      const diff = target.diff(dayjs(), "second");
      setRemaining(Math.max(0, diff));
    };

    // targetTime이 변경될 때 즉시 한 번 계산하여 싱크 맞춤
    calculate();
    const intervalId = setInterval(calculate, 1000);

    return () => clearInterval(intervalId);
  }, [targetTime]);

  return remaining;
}
